import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import logo from '../assets/Logo.png';

const Header = () => {
    const [categories, setCategories] = useState([]);

    useEffect(() => {
        axios.get('http://localhost:5000/api/categories')
            .then(res => setCategories(res.data))
            .catch(err => console.error("Erreur API:", err));
    }, []);

    return (
        <header className="navbar navbar-expand-md navbar-light bg-white border-bottom sticky-top">
            <div className="container">
                <Link className="navbar-brand" to="/"><img src={logo} alt="Logo" style={{ width: '200px' }} /></Link>

                <button className="navbar-toggler" type="button" data-bs-toggle="collapse" data-bs-target="#navbarNav">
                    <span className="navbar-toggler-icon"></span>
                </button>

                <div className="collapse navbar-collapse justify-content-end" id="navbarNav">
                    <ul className="navbar-nav fw-bold">
                        {categories.map((cat) => (
                            <li className="nav-item" key={cat.id}>
                                <Link className="nav-link text-dark px-2" to={`/category/${cat.id}`}>{cat.name}</Link>
                            </li>
                        ))}
                    </ul>
                </div>
            </div>
        </header>
    );
};

export default Header;
